using UnityEngine;

/// <summary>
/// Postura de escudo (Tartaruga Marinha — P5): enquanto o botão de habilidade
/// está seguro, o player fica em guarda: dano recebido reduzido (em cima da
/// Defesa da forma — ver PlayerCombat.TryDamagePlayer) e movimento travado.
///
/// Activado via PrimaryAbility.ShellGuard (AbilityRouter: StartGuard ao
/// pressionar, StopGuard ao soltar).
/// </summary>
[RequireComponent(typeof(PlayerMotor2D))]
public class ShellGuardAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Header("Escudo")]
    [Tooltip("Dano adicional reduzido enquanto em guarda (depois da Defesa da forma). O dano nunca desce abaixo de 'minDamage'.")]
    [Min(0)] public int guardDamageReduction = 1;

    [Tooltip("Dano mínimo que ainda passa com a guarda levantada (0 = pode anular por completo).")]
    [Min(0)] public int minDamage = 0;

    private PlayerMotor2D motor;
    private bool enabledForForm;

    /// <summary>true enquanto a guarda está levantada (lido por PlayerCombat.TryDamagePlayer).</summary>
    public bool IsGuarding { get; private set; }

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && form.primaryAbility == PrimaryAbility.ShellGuard;
        StopGuard();
    }

    public void StartGuard()
    {
        if (!enabledForForm || IsGuarding) return;

        IsGuarding = true;
        motor.SetMovementLocked(true, this);
    }

    public void StopGuard()
    {
        if (!IsGuarding) return;

        IsGuarding = false;
        motor.SetMovementLocked(false, this);
    }

    /// <summary>Aplica a redução da guarda ao dano (chamado por PlayerCombat.TryDamagePlayer).</summary>
    public int ApplyGuard(int damage)
    {
        if (!IsGuarding || damage <= 0) return damage;
        return Mathf.Max(minDamage, damage - guardDamageReduction);
    }

    // ---- IAbility (item 8) ----
    void IAbility.Activate() => StartGuard();
    void IAbility.Release() => StopGuard();
    public void Cancel(AbilityCancelReason reason) => StopGuard();
    public float CooldownRemaining => 0f;
    bool IAbility.IsActive => IsGuarding;

    // ---- IActiveAbility (Tarefa #34 — HUD) ----
    // Sem cooldown: a HUD não mostra indicador para esta habilidade.
    public float CooldownDuration => 0f;
    public bool CanActivate => enabledForForm && !IsGuarding;

    /// <summary>AnimalsDebugPanel — sem cooldown próprio (no-op).</summary>
    public void ResetCooldown() { }
}
